var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"오늘은 우리는 특별한 소망을 위해 이 자리에 모였습니다.","JPN":"今日私たちは、特別な願いのためにここに集まりました。","ENG":"Today, we have gathered here for a special wish.","TWN":"今天，我們為了特別的願望聚集於此。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"세계의 종말 이후, 다신 없을 평온한 삶을 낙원이란 이름으로 대가 없이 베풀었던 황금나무는...","JPN":"世界の終末後、二度とない穏やかな暮らしを楽園という名のもとに無償で与えてくれた黄金の木は……","ENG":"The Golden Tree, which granted us the peaceful life called the Promised Land after the end of the world without asking anything in return...","TWN":"在世界末日後，以樂園之名，無私奉獻再也不會擁有的和平生活的黃金樹……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"지금 외적으로부터 그 존재를 위협 받고 있습니다.","JPN":"今、外部からその存在を脅かされています。","ENG":"is now being threatened from the outside.","TWN":"如今正受到外部的威脅。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그러니 여러분께선 부디...","JPN":"ですから皆さんはどうか……","ENG":"So I ask that you all...","TWN":"因此請各位……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"오늘 하루, 우리의 소망을 위해서가 아닌 황금나무를 위해 기도를 올려주셨으면 합니다.","JPN":"今日1日は、私たちの願いではなく黄金の木のために祈りを捧げてください。","ENG":"Today, offer your prayers not for your own wishes, but for the Golden Tree.","TWN":"今天這一天，不是為了我們的願望，而是為了黃金樹祈禱。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"걱정마십시오, 사제님. 낙원을 위해 저의 소망을 바치겠습니다.","JPN":"心配には及びません、司祭様。楽園のために私の願いを捧げます。","ENG":"Don't worry, Father. I will offer my wish for the sake of the Promised Land.","TWN":"請放心，司祭。我願將我的願望奉獻給樂園。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"MAN_ANAP_NULL_NULL","text":{"KOREA":"비록 찰나였으나 우리 모두 해가 저물며 밤이 도래하는 광경을 똑똑히 보았습니다, 사제님. 그것은 예언의 때가 도래했단 뜻이죠.","JPN":"私たちは皆、一瞬でしたが日が暮れて夜が到来する景色をこの目で見ました、司祭様。それはついに予言の時が来たということなのでしょう。","ENG":"Though it was only for a moment, we all clearly witnessed the sun set and night fall, Father. That means the time of prophecy has come.","TWN":"雖然只是片刻，但我們都清楚地看見了日落與夜晚降臨，司祭。那正是預言之時到來的證明。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"암군 타기리온이 가져왔던 종말의 비극을 한시도 잊은 적 없답니다. 그걸 막기 위해서라면 소망 뿐만 아니라 제 목숨도 바치겠어요.","JPN":"暗君タギリオンがもたらした終末の悲劇を、一瞬たりとも忘れたことはありません。それを止められるなら、願いだけでなくこの命も捧げます。","ENG":"I have never forgotten, not even for a moment, the tragedy of the end that the Ignorant Monarch Thagirion brought. If it's to stop that, I would offer not only my wish but even my life.","TWN":"我從未忘記暗君塔基里翁帶來的末日悲劇。為了阻止它，不只是願望，我願意連性命都奉上。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WOMAN_ANAP_NULL_NULL","text":{"KOREA":"저도 마찬가지에요.","JPN":"私もです。","ENG":"As do I.","TWN":"我也是。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L15_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"우리는 사상도, 이념도, 태어나 살아온 시기도 달랐으나, 공동의 소망을 품고 있습니다.","JPN":"私たちは思想も、理念も、生きた時代も異なりますが、共通の願いを抱いています。","ENG":"Though our beliefs, ideals, and the times we were born and lived in are all different, we share a common wish.","TWN":"我們的思想、理念、出生與時代都不同，但我們擁有共同的願望。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그것은, 암군 타기리온으로부터 더 이상 누구도 고통 받지 않는 세계... 완전한 낙원, 아나필리스를 완성하는 것.","JPN":"それはこれ以上誰も暗君タギリオンに苦しめられない世界……完全なる楽園、アナピリスを完成すること。","ENG":"That wish is to complete a world where no one suffers any longer because of the Ignorant Monarch Thagirion... The perfect Promised Land, Anapilis.","TWN":"那就是不再讓任何人因暗君塔基里翁而痛苦的世界……完成真正的樂園，阿納菲莉絲。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"이제 그 예언의 실현이 머지 않았으니...","JPN":"そしてその予言の実現は目前に来ています……","ENG":"Now that the fulfillment of that prophecy is near...","TWN":"如今預言的實現已近在眼前……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"...다 함께 기도합시다.","JPN":"……皆さん共に、祈りを捧げましょう。","ENG":"...Let us all pray together.","TWN":"……讓我們一同祈禱吧。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_FENRIR_CA_HILDE_PR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"무슨... 소리지?","JPN":"何の……音？","ENG":"What... is that sound?","TWN":"什麼……聲音？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"방금 전까지만 해도 고통스러웠는데... 지금은 따스한 기운이 온몸을 감싸고 있어.","JPN":"さっきまで苦しかったのに……今は温かい気配に全身を包まれている。","ENG":"Just a moment ago I was in pain... but now a warm presence is wrapping around my whole body.","TWN":"剛才明明還很痛苦……現在全身卻被溫暖的氣息包圍。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"깨어나셨군요, 늑대 씨.","JPN":"起きたんですね、オオカミさん。","ENG":"You've awakened, Wolf.","TWN":"你醒了，狼。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...넌? 누구지?","JPN":"……あなたは？　誰？","ENG":"...You? Who are you?","TWN":"……你是？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"제 이름은 아우드라. 당신을 이곳에서 아주 오랫동안 기다렸죠.","JPN":"私の名前はアウドラ。とても長い間、ここであなたを待っていました。","ENG":"My name is Audra. I've been waiting for you here for a very long time.","TWN":"我的名字是奧德拉，我已在這裡等你很久了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"날... 기다리고 있었다고?","JPN":"私を……待っていた？","ENG":"You've... been waiting for me?","TWN":"等……我？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"난 분명 마왕 타기리온을 막으려고... 왔는데...","JPN":"私は確か魔王タギリオンを食い止めに……来たはずだけど……","ENG":"I definitely came here... to stop the Demon Lord Thagirion...","TWN":"我明明是為了阻止魔王塔基里翁……才來的……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"여긴 대체 어디지?","JPN":"ここはどこ？","ENG":"Where exactly is this place?","TWN":"這裡到底是哪裡？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이곳은 낙원.","JPN":"ここは楽園。","ENG":"This is the Promised Land.","TWN":"這裡是樂園。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신들이 다다르고 싶어했던, 설산의 꼭대기이자, 타기리온의 옥좌가 있는 곳이기도 하죠.","JPN":"あなたたちが目指していた雪山の頂上であり、タギリオンの玉座がある場所でもあります。","ENG":"The summit of the snowy mountain you were trying to reach... and the place where Thagirion's throne lies as well.","TWN":"也是你們想抵達的雪山山頂，同時也是塔基里翁王座所在地。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...뭐?","JPN":"……え？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아이들이 뛰어 놀고 있어.","JPN":"子どもたちが駆け回ってる。","ENG":"Children are running around.","TWN":"孩子們在奔跑玩耍。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하늘은 푸르고, 새소리도 들리는데.","JPN":"空は青く、鳥のさえずりも聞こえる。","ENG":"The sky is blue, and I can hear birds singing.","TWN":"天空湛藍，還聽得到鳥鳴。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이게 정말... 한 차례 멸망을 겪었던 세계란 거야?","JPN":"本当にここが……一度滅びを経験した世界だって言うの？","ENG":"Is this really... a world that already faced destruction once?","TWN":"這真的是……曾經毀滅過一次的世界嗎？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이건 누군가의 아름다운 추억이 소망으로 구현된 풍경일 뿐이에요.","JPN":"これは誰かの美しい思い出が願いとして具現化した景色にすぎません。","ENG":"This is only a landscape shaped from someone's beautiful memories made manifest through a wish.","TWN":"這只是某人的美好回憶，以願望具現化的景象而已。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"죽은 사람들은 지난 과거를 추억 할 뿐, 새로운 기억은 만들어내지 못하거든요.","JPN":"死んだ人は過去の思い出を振り返ることはできても、新しい記憶を生み出すことはできませんから。","ENG":"The dead can only recall the past they once lived. They can't create new memories.","TWN":"因為死去的人只能回憶過去，無法創造新的記憶。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대체 뭘 위해서... 죽은 사람들을 되살리고 소망까지 이뤄주는 거지?","JPN":"いったい何のために……死んだ人を蘇らせて、願いまで叶えてあげるの？","ENG":"Then what is the point... of reviving the dead and even granting their wishes?","TWN":"那到底是為了什麼……讓死人復活，甚至實現他們的願望？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"생전의 소망을 되풀이할수록, 잃어버렸던 삶에 대한 희망도 커지기 마련.","JPN":"生前の願いを噛みしめるほど、失った生への希望も大きくなるものです。","ENG":"The more they repeat the wishes they held in life, the more their hope for the life they lost grows as well.","TWN":"生前的願望被反覆實現時，對失去人生的希望也會因而增長。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이곳 주민들 한 사람 한 사람이 얼마나 큰 희망을 품고 있을지, 짐작이 되세요?","JPN":"ここの住民一人ひとりが抱いている希望がどれほど大きいか、想像できますか？","ENG":"Can you imagine how great the hope each and every one of the people here must hold?","TWN":"你能想像這裡的每個人，懷抱著多大的希望嗎？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저들이 품고 있는 건 희망이 아니라 미련이겠지. 당신이 말하는 낙원이나 소망 같은 건 그저 지난 추억을 되풀이하는 것 뿐이니까.","JPN":"彼らが抱いているのは希望じゃなくて未練でしょ。あなたの言う楽園とか願いとかは、ただ過去の思い出を繰り返してるだけなんだから。","ENG":"What they hold isn't hope. It's regret. The Promised Land and wishes you speak of are nothing more than repeating old memories.","TWN":"他們懷抱的不是希望，而是執念吧，你所說的樂園與願望，不過是重複過去的回憶罷了。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"결국 세계가 타기리온의 손에 멸망했다는 사실은 변하지 않아.","JPN":"結局のところ、世界がタギリオンによって滅ぼされたという事実は変わらない。","ENG":"In the end, the fact that the world was destroyed by Thagirion doesn't change.","TWN":"世界被塔基里翁毀滅的事實並沒有改變。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...그 말이 맞아요.","JPN":"……その通りです。","ENG":"...That's true.","TWN":"……你說得沒錯。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"저들은 낙원의 힘으로 소망을 이뤘지만, 그럼에도 여전히 타기리온을 원망하고 있죠.","JPN":"彼らは楽園の力で願いを叶えた今も、タギリオンを恨んでいます。","ENG":"They fulfilled their wishes through the power of the Promised Land, yet they still resent Thagirion.","TWN":"他們雖然藉由樂園的力量實現願望，但仍然怨恨著塔基里翁。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"낙원을 창조할 정도의 힘이라면, 타기리온에 대한 악몽 같은 건 그냥 지워버릴 수도 있었을 텐데.","JPN":"楽園を作るほどの力なら、タギリオンに関する辛い記憶を消すことだってできただろうに。","ENG":"If there's enough power here to create a place like the Promised Land, then something like the nightmare of Thagirion could have simply been erased.","TWN":"既然有創造樂園的力量，那應該也能輕易抹除關於塔基里翁的惡夢吧？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"왜 그 사람들이 타기리온을 원망하도록 내버려둔 거야?","JPN":"なんでみんながタギリオンを恨むように放っておくの？","ENG":"So why did you leave them to keep resenting Thagirion?","TWN":"為什麼要讓他們繼續怨恨呢？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"괴로운 과거를 잊어서는 희망을 얻을 수 없으니까요.","JPN":"辛い過去を忘れてしまうと希望が得られないからです。","ENG":"Because hope can't exist if painful memories are forgotten.","TWN":"若忘記痛苦的過去，就無法獲得希望。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"언젠가, 타기리온에게 복수할 수 있을 거라는 희망을 품게 하는 거죠.","JPN":"いつかタギリオンに復讐できるという希望を持たせるんですよ。","ENG":"They must be allowed to hold on to the hope that one day they can take revenge on Thagirion.","TWN":"讓他們懷抱著總有一天能向塔基里翁復仇的希望。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런 건... 기만이야.","JPN":"そんなの……欺瞞だよ。","ENG":"That's... deception.","TWN":"那只是……欺瞞而已。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"타기리온은 지금껏 멀쩡히 살아 움직이며 수많은 세계를 집어 삼켜왔어. 그리고 이젠 우리 세계도.","JPN":"タギリオンは今まで死ぬこともなく、多くの世界を滅ぼしてきた。今回は私たちの世界までね。","ENG":"Thagirion is still alive and moving even now, devouring countless worlds. And now ours as well.","TWN":"塔基里翁至今仍活著，吞噬無數世界。現在甚至輪到我們的世界。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런데 넌 정작 이 사람들을 낙원 안에 가둔 채, 복수라는 영원히 이루지 못할 헛된 희망만 붙잡게 하고 있지.","JPN":"でもあなたはこの人たちを楽園の中に閉じ込めて、復讐という永遠に叶えられない虚しい希望に縋らせている。","ENG":"And yet you've locked these people inside the Promised Land, leaving them clinging only to the empty hope of revenge they can never fulfill.","TWN":"但你卻把這些人困在樂園裡，只讓他們抓著永遠無法實現的復仇幻想。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그건, 헛된 희망이 아녜요.","JPN":"虚しい希望ではありません。","ENG":"That isn't an empty hope.","TWN":"那並不是虛假的希望。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"언젠가 이뤄질 현실인걸요.","JPN":"いつかは叶う現実です。","ENG":"It's a reality that will one day come true.","TWN":"而是終將成真的現實。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭, 날 묶어둔 이유가 뭐지? 무슨 짓을 할 셈이야?!","JPN":"くっ……どうして私を拘束した？　何をするつもり！？","ENG":"Kgh, why have you bound me? What are you trying to do?!","TWN":"可惡，你為什麼綁住我？你想做什麼？！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이 꽃은 운명을 끊어낼 수 있는 흰 서리꽃.","JPN":"この花は運命を断ち切ることのできる白い霜の花。","ENG":"This flower is the white frost flower that can sever fate.","TWN":"這朵花是能斬斷命運的白霜花。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"전 지금부터 이걸로 당신이 가진 늑대의 운명을 끊어내는 의식을 치를 거에요.","JPN":"私は今からこれで、あなたの持つオオカミの運命を断ち切る儀式を行います。","ENG":"From this moment on, I will perform a ritual with it to sever the Wolf's fate you carry.","TWN":"我現在要用它進行儀式，斬斷你身為狼的命運。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐라고...? 대체 왜 그런 짓을 하는 거야?","JPN":"何だって……？　何でそんなことをする？","ENG":"What...? Why would you do something like that?","TWN":"什麼……？你為什麼要這麼做？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"모든 마왕은 대적자의 길을 거쳐요.","JPN":"すべての魔王は敵対者の道を通ります。","ENG":"Every Demon Lord passes through the path of the Antagonist.","TWN":"所有魔王都會經歷敵對者之路。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"마왕으로부터 세상을 구할 운명임에도, 실패하고 전락할 운명 또한 타고나죠.","JPN":"魔王から世界を救う運命にありながら、失敗し身を落とす運命にもある。","ENG":"Though they are fated to save the world from the Demon Lord, they are also born with the fate to fail and fall.","TWN":"注定要從魔王手中拯救世界，卻也註定失敗墮落。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그렇다면 세상은 왜 대적자를 만들어내는 걸까요?","JPN":"なら、世界はなぜ敵対者を生み出すのでしょうか？","ENG":"Then why does the world create Antagonists?","TWN":"那麼，世界為何要創造敵對者？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"대적자로서 세상을 구하는 것과 마왕이 되어 세상을 부수는 것엔 어떤 차이가 있는 걸까요?","JPN":"敵対者として世界を救うことと、魔王になって世界を壊すことは何が違うのでしょうか？","ENG":"What is the difference between saving the world as an Antagonist and destroying it as a Demon Lord?","TWN":"成為敵對者拯救世界與成為魔王毀滅世界，有何不同？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"카운터가 힘을 잃고 그림자가 되는 것처럼, 모든 것엔 양면이 있을 뿐이야.","JPN":"カウンターが力を失ってシャドウになるように、すべてには裏と表があるだけだよ。","ENG":"Just like how a Counter loses its power and becomes a Shadow, everything simply has two sides.","TWN":"就像制裁者失去力量會成為暗影一樣，所有事物都是一體兩面。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"운명이란 건 바꿀 수 있어! 대적자라고 해서 반드시 마왕이 되는 건 아니라고!","JPN":"運命は変えられるんだ！　敵対者だからって必ず魔王になるわけじゃない！","ENG":"Fate can be changed! Just because someone is an Antagonist doesn't mean they have to become a Demon Lord!","TWN":"命運是可以改變的！敵對者不一定會成為魔王！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...아뇨. 대적자는 실패해요. 가장 전능한 존재가 그렇게 만들었으니까요.","JPN":"……いいえ、敵対者は失敗します。最も全能なる存在がそう創造したのですから。","ENG":"...No. Antagonists fail. Because the most powerful being made it that way.","TWN":"……不，敵對者會失敗，因為最全能的存在就是如此安排的。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"가장 전능한 존재라니...?","JPN":"もっとも全能なる存在……？","ENG":"The most powerful being...?","TWN":"最全能的存在……？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"전능한 존재는 대적자에게 마왕이 될 운명을 쥐어주고, 마왕을 처단해 그 힘을 흡수할 수 있는 늑대라는 존재를 만들었어요.","JPN":"全能なる存在は敵対者に魔王となる運命を与え、魔王を処断してその力を吸収できるオオカミという存在を作りました。","ENG":"The most powerful being gave the Antagonist the fate of becoming a Demon Lord, and created the being called the Wolf to slay the Demon Lord and absorb that power.","TWN":"祂賦予敵對者成為魔王的命運，同時創造了處決魔王、吸收其力量的狼。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"왜 그런 선택을 했을까요?","JPN":"なぜそんな選択をしたのでしょうか？","ENG":"Why do you think it made that choice?","TWN":"為什麼要選擇這麼做呢？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"마왕이 된다는 건, 자신이 멸망 시킨 세상의 모든 가능성을 품게 된다는 뜻이죠.","JPN":"魔王になるということは、己が滅ぼした世界のすべての可能性を取り込むということ。","ENG":"To become a Demon Lord means to contain all the possibilities of the world one has destroyed.","TWN":"成為魔王，就意味著承載被自己毀滅的世界中所有可能性。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그렇다면 대적자는... 처음부터 늑대에게 수확 될 운명으로 태어난 게 아닐까요?","JPN":"ならば、敵対者は……最初からオオカミに狩られる運命に生まれたのではないでしょうか。","ENG":"If that's the case, then perhaps the Antagonist... was born from the beginning with the fate of being harvested by the Wolf.","TWN":"那麼敵對者……是否一開始就是為了被狼收割而誕生的呢？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...아니야.","JPN":"……違う。","ENG":"...No.","TWN":"……不。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"난... 레이 선배를 해치고 싶지 않았어.","JPN":"私は……レイ先輩を殺したくなかった。","ENG":"I... didn't want to kill Ray.","TWN":"我……不想殺死雷伊前輩。"},"stage":{"bg":"MS_1113_1","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"하지만 네헤모트는 죽었고, 대적자가 시기 좋게 그 힘을 빼앗았죠.","JPN":"ですがネヘモトは死に、敵対者がタイミング良くその力を奪いました。","ENG":"But Nehemoth died, and the Antagonist took that power at just the right moment.","TWN":"但貝赫莫特已經死了，而敵對者恰巧奪走了那份力量。"},"stage":{"bg":"MS_1113_1","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그게 가능했던 건, 늑대인 당신이 네헤모트의 존재를 마왕이 아니라고 부정했기 때문이에요.","JPN":"それができたのは、オオカミであるあなたがネヘモトを魔王ではないと否定したからです。","ENG":"That was possible because you, as the Wolf, denied Nehemoth's existence as a Demon Lord.","TWN":"之所以能做到，是因為身為狼的你否定了貝赫莫特作為魔王的存在。"},"stage":{"bg":"MS_1113_1","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"늑대 앞에 선 네헤모트가 평범한 소년이 된 순간, 마왕 네헤모트는 죽은 셈인 거죠.","JPN":"オオカミの前に立ったネヘモトが平凡な少年になった瞬間、魔王ネヘモトは死んだのです。","ENG":"The moment Nehemoth standing before the Wolf became an ordinary boy, the Demon Lord Nehemoth was as good as dead.","TWN":"當站在狼面前的貝赫莫特成為普通少年時，就等於魔王貝赫莫特的死亡。"},"stage":{"bg":"MS_1113_1","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내가... 그 사람을 그렇게 만든 거라고?","JPN":"あの人がああなったのは……私のせいだって言うの？","ENG":"I... made that happen to him?","TWN":"是我……讓他變成那樣的？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"알아요. 당신이 그런 결말을 원하지 않았다는 건.","JPN":"あなたがそんな結末を望んでいなかったということは知っています。","ENG":"I know. I know you never wanted that kind of ending.","TWN":"我知道，你並不希望那樣的結局。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그러니 도와줄게요. 당신이 더 이상 늑대로서 고통 받지 않도록.","JPN":"だから手伝います。あなたがこれ以上オオカミとして苦しまないように。","ENG":"So I'll help you. So that you won't suffer any longer as the Wolf.","TWN":"所以我會幫你，讓你不再因為身為狼而痛苦。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...그 운명을 끊어내 줄게요.","JPN":"……その運命を断ち切ってあげます。","ENG":"...I will sever that fate.","TWN":"……我會斬斷那個命運。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...앗. 방금 그건 뭐였지?","JPN":"……あっ、今のは？","ENG":"...Ah. What was that just now?","TWN":"……咦，剛才那是什麼？"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"하늘의 궤적을 따라... 무언가가 추락했어.","JPN":"空の軌跡に沿って……何かが落ちた。","ENG":"Something followed a trail across the sky... and then fell.","TWN":"有東西沿著天空的軌跡……掉下來了。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"날개가 달린 것 같았는데...","JPN":"翼が生えてた気がするけど……","ENG":"It looked like it had wings...","TWN":"好像有翅膀……"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...설마, 천사?","JPN":"……まさか、天使？","ENG":"...Could it be an angel?","TWN":"……難道，是天使？"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"하늘이 갈라지고 어둠이 내려앉아도, 우리는 변함없이 기도하리라.","JPN":"天が裂かれ暗闇が訪れるとしても、我らは変わらず祈ろう。","ENG":"Even if the heavens split apart and darkness descends, we shall pray without faltering.","TWN":"即使天空分裂、黑暗降臨，我們仍會祈禱。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이 땅에 천사가 내려오고, 노랫소리가 울려 퍼지면, 우리의 정적 또한 심판 받을 지니.","JPN":"この地に天使が降り立ち、歌声が響けば、我らの政敵もまた審判されよう。","ENG":"When angels descend upon this land and song echoes through the air, our foe shall face judgment as well.","TWN":"當天使降臨這片土地、歌聲響起時，我們的寂靜也將受到審判。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"우리가 비원을 이루는 그날- 가을 끝무렵의 침묵 속에서, 비로소 낙원은 완성되리라.","JPN":"我らの悲願が叶うその日……晩秋の沈黙の中で、ついに楽園は完成されるだろう。","ENG":"On the day our wish is fulfilled. Within the silence at the end of autumn, the Promised Land shall at last be complete.","TWN":"在我們願望實現的那一天—樂園終將在秋末的沉默中完成。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"착륙은 성공적이었습니다. 무사합니까, 휴먼?","JPN":"着陸は成功しました。無事ですか？　ヒューマン。","ENG":"Landing was successful. Are you unharmed, human?","TWN":"著陸成功。你沒事吧，人類？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...무사한 것 같군.","JPN":"……無事のようだな。","ENG":"...I seem to be all right.","TWN":"……看來沒事。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그나저나, 이렇게 보는 눈이 많은 한복판에 떨어질 줄은 몰랐는데 말이지.","JPN":"それにしても、こうも人目に付く場所に落ちるとは想像もしなかったのだが。","ENG":"Still, I didn't expect we'd land right in the middle of so many eyes watching us.","TWN":"不過我沒想到會在這麼多人注視中降落。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GIRL_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"...적진이란 걸 잊지 마십시오. 휴먼의 탈을 쓴 괴물일 가능성이 있습니다.","JPN":"……ここは敵陣だということを忘れないでください。ヒューマンの皮を被った化け物である可能性があります。","ENG":"...Don't forget that this is enemy territory. They may be monsters wearing human masks.","TWN":"……別忘了這裡是敵營，也可能是披著人類外皮的怪物。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"먼저 접근해오기 전에 한 번에...","JPN":"向こうから近づいてくる前に、一気に……","ENG":"Before they approach us, I will eliminate them all at once–","TWN":"在他們接近前，一次解決……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MAN_ANAP_NULL_NULL","text":{"KOREA":"...천사다.","JPN":"……天使だ。","ENG":"...An angel.","TWN":"……是天使。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WOMAN_ANAP_NULL_NULL","text":{"KOREA":"예언의 천사께서 내려오셨어.","JPN":"予言にあった天使が降臨したわ。","ENG":"The prophesied angel has descended.","TWN":"預言中的天使降臨了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사람들이 자네 앞에 무릎을 꿇고 엎드리는군.","JPN":"皆が君を前にひれ伏しているな。","ENG":"They're kneeling and bowing before you.","TWN":"大家都跪在你面前了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우릴 방심 시키려는 수작으로 보이나?","JPN":"我々を油断させるためだと思うか？","ENG":"Is this some kind of trick to make us lower our guard?","TWN":"這是想讓我們放鬆警戒的手段嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"...스캔 결과. 무기를 숨겨두고 있진 않군요.","JPN":"……スキャン結果、武器を隠し持ってはいませんね。","ENG":"...Scan results. They are not concealing any weapons.","TWN":"……掃描結果，沒有藏匿武器。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"감정적으로도 전혀 동요하고 있지 않습니다.","JPN":"感情的にもまったく動揺が見られません。","ENG":"Emotionally as well, they show no signs of agitation.","TWN":"情緒也沒有任何動搖。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"아아, 천사여. 부디 우리의 정적을 심판해주소서.","JPN":"ああ、天使よ。どうか我々の政敵に裁きを下してください。","ENG":"Ah, angel. Please judge our foe.","TWN":"啊啊，天使啊，請審判我們的敵人吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"질문하겠습니다. 당신들이 말하는 정적이 누구입니까?","JPN":"質問します。あなたたちの言う政敵とは誰ですか。","ENG":"I have a question. Who is the foe you speak of?","TWN":"請問你們所說的敵人是誰？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"그자는 세계를 멸망 시키는 암군이자, 타기리온이라는 이름으로도 불립니다.","JPN":"あの者は世界を滅ぼす暗君であり、タギリオンという名で呼ばれています。","ENG":"She is the Ignorant Monarch who brings about the destruction of the world, also known by the name Thagirion.","TWN":"她是毀滅世界的暗君，也被稱為塔基里翁。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"저희는 황금나무의 예언을 통해, 그자가 심판 받기를 기다렸답니다. 그리고 당신께선 그 예언의 필두에 계신 분이지요.","JPN":"私たちは黄金の木の予言通り、あの者が裁きを受ける時を待っていました。そしてあなたはその予言の筆頭にいるお方です。","ENG":"Through the prophecy of the Golden Tree, we have been waiting for the day she would be judged. And you are the one who stands at the forefront of that prophecy.","TWN":"我們透過黃金樹的預言等待她被審判，而您正是預言的領導人。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"...타기리온이 어디에 있는지 알고 있습니까?","JPN":"……タギリオンがどこにいるか知っていますか。","ENG":"...Do you know where Thagirion is?","TWN":"……你們知道塔基里翁在哪裡嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BOY_ANAP_NULL_NULL","text":{"KOREA":"타기리온은 겨울을 몰고 다녀요. 겨울이 있는 곳이라면 어디에나 존재하죠.","JPN":"タギリオンは冬を連れています。冬がある場所ならどこにでも存在します。","ENG":"Thagirion brings winter wherever she goes. Wherever there is winter, she exists.","TWN":"塔基里翁會帶來冬天，有冬天的地方就有她。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WOMAN_ANAP_NULL_NULL","text":{"KOREA":"겨울이 없는 낙원에 얼마 전 처음으로 눈이 내렸어요. 어쩌면 밤이 온 그날, 그자가 이곳에 숨어든 걸지도 몰라요.","JPN":"冬のない楽園に、この前初めて雪が降りました。もしかしたら夜が来たあの日、タギリオンが楽園に潜り込んだのかもしれません。","ENG":"Snow fell in the Promised Land for the first time not long ago, where there had never been winter before. Perhaps on the day night came, she slipped into this place.","TWN":"原本沒有冬天的樂園，最近第一次下了雪。或許她已經在那個夜晚潛入這裡。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"겨울이 있는 곳에 존재한다라... 다소 추상적이지만, 참고해두겠습니다.","JPN":"冬がある場所に存在する、ですか……多少抽象的ですが、参考にします。","ENG":"She exists wherever there is winter... It's rather abstract, but I'll keep it in mind.","TWN":"存在於有冬天之處……雖然有些抽象，但我會記得這一點。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하늘이 맑으니, 적어도 지금 당장 타기리온은 이곳에 없는 모양이군.","JPN":"空は晴れているし、少なくとも今ここにタギリオンはいないようだ。","ENG":"The sky is clear, so at least for now it seems Thagirion isn't here.","TWN":"至少現在天空晴朗，塔基里翁不在這裡。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"저 역시 데이터에 기록된 타기리온의 신성 파형은 감지되지 않는군요.","JPN":"私のデータに記録されているタギリオンの神聖波形も感知されません。","ENG":"I also detect no Divinity waveform of Thagirion recorded in the data.","TWN":"我也沒有偵測到資料中記錄的神性波形。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"그럼 처음 계획한대로...","JPN":"なら、最初に計画した通り……","ENG":"Then as originally planned...","TWN":"那麼照原定計畫……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"...뭡니까? 너는.","JPN":"……何ですか、あなたは。","ENG":"...What are you?","TWN":"……你是誰啊？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WOMAN_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"그 질문에 답할 의무는 없습니다.","JPN":"その質問に答える義務はありません。","ENG":"I have no obligation to answer that question.","TWN":"我沒有義務回答。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"침입자는 다만 배제할 뿐.","JPN":"侵入者は排除するだけです。","ENG":"Intruders will simply be eliminated.","TWN":"只需要排除入侵者。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"이곳에 방문한 이래, 제가 만난 가장 무례한 객체군요.","JPN":"私がここに来てから遭遇した中で一番無礼な個体ですね。","ENG":"Since arriving here, you are the rudest entity I have encountered.","TWN":"這是我來到這裡後，遇到最無禮的對象。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"좀 걸릴 테니 먼저 가십시오, 휴먼. 나중에 따라잡겠습니다.","JPN":"少しかかりそうなので先に行ってください、ヒューマン。後で追いつきます。","ENG":"This may take some time, so please go on ahead, human. I will catch up later.","TWN":"好像會花點時間，你先走吧，人類。我之後會追上你。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...부탁하지.","JPN":"……頼む。","ENG":"...I'll leave it to you.","TWN":"……拜託你了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이봐. 거기 아무도 없어?","JPN":"ねえ、そこ誰もいないの？","ENG":"Hey. Is anyone there?","TWN":"喂，那邊有人嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 인형 녀석. 갑자기 어디로 사라진 거지?","JPN":"あの人形のやつ、急にどこに消えたんだろう？","ENG":"That doll. Where did she suddenly disappear to?","TWN":"那個人偶……怎麼突然消失了？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하, 아까부터 살펴봤지만 열쇠 구멍은커녕 문조차 없는 감옥이라니. 평생 여기 가둬 놓을 작정이었나?","JPN":"はあ、さっきから調べてるけど鍵穴どころかドアもない牢屋だなんて。一生ここに監禁するつもりだったのかな。","ENG":"*Sigh* I've been looking around for a while now, but a prison with not even a keyhole, let alone a door? Were they planning to keep me locked up here forever?","TWN":"雖然我剛剛找過了，這裡連門和鑰匙孔都沒有，還能叫監獄？是想把我關一輩子嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"하아... 하...","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"찾았다.","JPN":"見つけた。","ENG":"There you are.","TWN":"找到了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아...? 여긴 어떻게 온 거야?","JPN":"エクレシア……？　どうやってここまで来たの？","ENG":"Ecclesia...? How did you get here?","TWN":"艾可露西亞……？你怎麼來的？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"갑자기 누군가 지붕을 뚫고 솟구쳐 오르기에, 수상쩍어 보여서 왔사옵니다.","JPN":"突然誰かが屋根を突き破って飛び立ったので、怪しいと思って来たのでございます。","ENG":"Someone suddenly burst up through the roof, so I came because it seemed suspicious.","TWN":"有人突然從屋頂衝出來。看起來很可疑，所以我就過來了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아... 그 인형 녀석, 그런 식으로 요란하게 떠나긴 했지. 누가 침입했다고 중얼거렸어.","JPN":"あ……人形のやつ、そうやって派手に出ていったっけ。侵入者がいるとか呟いてた。","ENG":"Ah... that doll did leave in quite a flashy way. She muttered something about an intruder.","TWN":"啊，那個人偶確實大吵大鬧著離開了，還說有入侵者。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"침입자...? 낙원에 누군가 온 것입니까?","JPN":"侵入者……？　楽園に誰かが入ってきたのですか？","ENG":"An intruder...? Has someone come to the Promised Land?","TWN":"入侵者？有人來到樂園了嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"아니, 그보단 거기서 꺼내드리겠사옵니다!","JPN":"それより、今すぐそこから出してさしあげます！","ENG":"No. More importantly, I will get you out of there!","TWN":"先不說那個，我先救你出來！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"쉽지 않을 거야. 열쇠도 없고 문도 없어서...","JPN":"簡単じゃないと思うよ。鍵もないしドアもないから……","ENG":"It won't be easy. There's no key, and there's not even a door...","TWN":"沒那麼容易。這裡沒有門也沒有鑰匙……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...지금 팔 힘으로 철창을 휘어버린 거야? 연약한 몸인 줄 알았는데.","JPN":"……今、腕の力だけで鉄格子を曲げた？　華奢に見えるのに。","ENG":"...Did you just bend those bars with your arms? I thought you had a frail body.","TWN":"……你剛剛用手把鐵欄掰彎了？我還以為你很柔弱。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"이유는 모르겠으나... 기억을 되찾은 뒤로 힘이 돌아온 듯 하옵니다.","JPN":"理由は分かりませんが……記憶を取り戻したことで力も戻ってきたようでございます。","ENG":"I don't know why... but after regaining my memories, it seems my strength has returned as well.","TWN":"雖然不清楚原因……但恢復記憶後，力量似乎也回來了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"모르스 때의 기억이 돌아왔다고? 말투가 그대로라 눈치 못 챘어.","JPN":"モールスの時の記憶が戻ったの？　喋り方がそのままだから気づかなかったよ。","ENG":"Your memories from when you were Mors came back? I didn't even notice since the way you speak is the same.","TWN":"你恢復莫爾斯時期的記憶了？你的語氣沒變，我都沒發現。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그건 아마도, 이 몸의 옛 기억 역시 공존하고 있어 그러한 것이 아니 올지...","JPN":"それはおそらく、わたくしのかつての記憶も共存しているからではないでしょうか……","ENG":"That is likely because the girl's old memories also still coexist within me...","TWN":"大概是因為少女過去的記憶也同時存在，才會這樣吧……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"귀여운데 아무렴 어때. 얼른 이 망할 낙원이나 벗어나자.","JPN":"可愛いしそれはどうでもいいよ。早くこのふざけた楽園から出ていこう。","ENG":"You're cute, so what does it matter. Let's get out of this damned Promised Land already.","TWN":"很可愛就好了。先離開這個該死的樂園吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"낙원을 떠나다니요? 무슨 수로...?","JPN":"楽園を出ていく……？　どうやってですか……？","ENG":"Leave the Promised Land? But how...?","TWN":"離開樂園？要怎麼做……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아우드라가 <color=#ffd34c>낙원문</color>이란 곳의 위치를 알려줬어. 거길 통하면 밖으로 나갈 수 있을 거야.","JPN":"アウドラが<color=#ffd34c>楽園の門</color>というやつの場所を教えてくれたの。そこを通れば外に出られるはずだよ。","ENG":"Audra told me the location of a place called <color=#ffd34c>Avalon's Gate</color>. If we pass through there, we should be able to get outside.","TWN":"奧德拉告訴過我<color=#ffd34c>樂園門</color>的位置，應該可以從那裡出去。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"아우드라가...","JPN":"アウドラが……","ENG":"Audra...","TWN":"奧德拉……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그녀는 타기리온의 전신입니다. 정녕 그자의 말을 믿으시옵니까?","JPN":"彼女はタギリオンの前身です。本当にその言葉を信じるのでございますか？","ENG":"She is the former self of Thagirion. Do you truly intend to trust her words?","TWN":"她其實是塔基里翁的前身，你真的要相信她？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다른 꿍꿍이가 있을 수는 있겠지만... 적어도 내 눈에 연기하는 것처럼 보이진 않았어.","JPN":"何か企んでいるのかもしれないけど……少なくとも、演技をしているようには見えなかったよ。","ENG":"She might have some other motive... but at least to me, it didn't look like she was pretending.","TWN":"也許她有別的目的……但至少看起來不像在演戲。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신 생각은 어때? 걔가 거짓말을 했을 것 같아?","JPN":"君はどう思う？　アウドラが嘘をついていると思う？","ENG":"What do you think? Do you think she was lying?","TWN":"你覺得呢？她會說謊嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"저의 기억에도, 거짓말을 할 줄 아는 아이는 아니었습니다.","JPN":"わたくしも、嘘がつけるような子ではなかったと記憶しております。","ENG":"In my memories as well, she was not a child who knew how to lie.","TWN":"在少女的記憶裡，她不是會說謊的人。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아우드라는 지금껏 한순간도 악의를 드러내지 않았어.","JPN":"アウドラは今まで一瞬も悪意を表に出したことがない。","ENG":"Audra has not shown a single moment of malice until now.","TWN":"奧德拉從未展現過惡意。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"네퀴티아인 날 원망할 수도 있었을 텐데. 오히려 낙원의 일원으로 받아주기까지 했지. 우릴 멋대로 이곳에 데려온 건 사실이지만... 지금은 믿어봐도 좋다고 생각해.","JPN":"ネキティアである私を恨むことだってできただろうに、楽園の一員として受け入れてくれた。私たちを勝手にここに連れてきたのは事実だけど……今は信じてもいいと思うんだ。","ENG":"She could have resented me for being Nequitia. Instead, she even accepted me as a member of the Promised Land. It's true she brought us here without permission... But I think it's all right to trust her for now.","TWN":"她應該會埋怨身為指揮家的我，但她反而接納我作為樂園的一員。雖然把我們帶來這裡……但我覺得可以相信她。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"조금 전 눈이 내리기 시작했으니 머잖아 마수들이 나타날 것입니다.","JPN":"少し前から雪が降り出したので、まもなく魔獣が現れるでしょう。","ENG":"Snow began to fall a short while ago, so before long the monsters will appear.","TWN":"不久前開始下雪了，等等魔獸就會出現。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"저도 레아 님과 낙원문까지 동행하겠사옵니다.","JPN":"わたくしもレア様と共に楽園の門まで同行いたします。","ENG":"I will accompany you to Avalon's Gate as well, Ms. Leah.","TWN":"我也會陪蕾亞小姐一起前往樂園門。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"좋아. 가자.","JPN":"よし、行こう。","ENG":"All right. Let's go.","TWN":"好，走吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그리고... 고마워.","JPN":"それと……ありがとう。","ENG":"And... thank you.","TWN":"還有……謝謝你。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"우릴 믿고, 함께 싸워줘서.","JPN":"私たちを信じて、共に戦ってくれて。","ENG":"For trusting us, and fighting alongside us.","TWN":"相信我們，和我們一起戰鬥。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...해가 저물고 있사옵니다.","JPN":"……日が暮れております。","ENG":"...The sun is setting.","TWN":"……太陽快下山了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"서두르시지요.","JPN":"急ぎましょう。","ENG":"We should hurry.","TWN":"我們得快點了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};